      "content": "const express = require('express');
const tasksService = require('../service');

const router = express.Router();

router.post('/', (req, res) => {
  const { title } = req.body;
  if (!title) {
    return sendError(res, 400, 'BadRequest', 'Title is required');
  }
  const task = tasksService.createTask(title);
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const tasks = tasksService.getTasks();
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!status || !['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'BadRequest', 'Invalid status');
  }
  const task = tasksService.updateTask(taskId, status);
  if (!task) {
    return sendError(res, 404, 'NotFound', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;
